const { SlashCommandBuilder } = require('discord.js');

module.exports = {
    data: new SlashCommandBuilder()
        .setName('ban')
        .setDescription('Ban a user')
        .addUserOption(option => 
            option.setName('user')
            .setDescription('The user to ban')
        )
        .addStringOption(option => 
            option.setName('reason')
            .setDescription('The reason for the ban')
            .setRequired(false)
        ),
    async execute(interaction, client) {
        try {
            const targetUser = interaction.options.getUser('user');
            const reason = interaction.options.getString('reason') || 'No reason provided';

            // Check if the user has the required permissions to ban someone
            if (!interaction.member.permissions.has('BAN_MEMBERS')) {
                await interaction.reply({ content: 'You do not have the required permissions to ban someone.', ephemeral: true });
                return;
            }

            // Ensure the bot has the necessary permissions to ban users
            if (!interaction.guild.me.permissions.has('BAN_MEMBERS')) {
                await interaction.reply({ content: 'I do not have the required permissions to ban someone.', ephemeral: true });
                return;
            }

            // Ban the user
            await interaction.guild.members.ban(targetUser.id, { reason: reason });

            // Send a success message
            await interaction.reply({ content: `User ${targetUser.tag} has been banned for the reason: ${reason}.`, ephemeral: true });
        } catch (error) {
            console.error(error);
            await interaction.reply({ content: 'An error occurred while trying to ban the user.', ephemeral: true });
        }
    },
};
```

### Key Improvements:
1. **Check for bot permissions**: The bot also needs the `BAN_MEMBERS` permission to ban users, so we added a check for `interaction.guild.me.permissions.has('BAN_MEMBERS')`.
2. **Use `interaction.guild.members.ban`**: This is the correct method to ban a user in Discord.js v14.
3. **Ensure `interaction.member` and `interaction.guild` are available**: These properties are necessary to check permissions and guild details.

